import{r as i,o as e,c as a,a as l,w as r,F as n,d as h,b as o}from"./app.2e1eaa90.js";const t={},s=h('<h1 id="介绍" tabindex="-1"><a class="header-anchor" href="#介绍" aria-hidden="true">#</a> 介绍</h1><p>Koishi 是一个基于 Node.js 的跨平台机器人框架。</p><p>它的名字和图标设计来源于东方 Project 中的角色古明地恋（Komeiji Koishi）。</p><h2 id="特性" tabindex="-1"><a class="header-anchor" href="#特性" aria-hidden="true">#</a> 特性</h2><h3 id="开箱即用的-cli" tabindex="-1"><a class="header-anchor" href="#开箱即用的-cli" aria-hidden="true">#</a> 开箱即用的 CLI</h3><p>Koishi 高度配置化的命令行工具可以让你无需写代码就搭建属于你的机器人。与此同时，CLI 还配备了丰富和人性化的提示，进一步提高调试体验。我们甚至还实现了<strong>插件级别的 HMR（模块热替换）</strong>，让你开发和调试插件也拥有如同前端开发一样的丝滑体验。</p>',6),u=o("参见："),d=o("快速上手"),p=l("h3",{id:"功能强大的-api",tabindex:"-1"},[l("a",{class:"header-anchor",href:"#功能强大的-api","aria-hidden":"true"},"#"),o(" 功能强大的 API")],-1),c=l("p",null,"经过了几个版本的迭代，Koishi 已经发展出了丰富的 API，功能覆盖机器人领域的方方面面。从上层负责交互的指令、会话、中间件，再到中层负责控制的应用、上下文、插件，最后到底层的机器人和适配器，每一个部分都经过了精心的编写，可以让你轻松实现任何需求。如果担心在复杂的功能中迷失方向，我们也准备了细致的文档来提供帮助。",-1),g=o("参见："),f=o("API 文档"),b=h('<h3 id="丰富的生态系统" tabindex="-1"><a class="header-anchor" href="#丰富的生态系统" aria-hidden="true">#</a> 丰富的生态系统</h3><p>Koishi 在编写时，也同样编写了大量的官方插件作为补充。它们有些作为 Koishi 的基础功能，有些则为 Koishi 的使用提供了许多便利。更重要的是，这数十个插件都可以作为 Koishi 插件开发的极好示范。下面是一些例子：</p><ul><li>koishi-plugin-schedule：管理计划任务</li><li>koishi-plugin-teach：教机器人说话</li><li>koishi-plugin-webui：网页控制台</li></ul><p>除了这些官方插件以外，社区贡献者也编写了各种各样的第三方插件：</p><ul><li>koishi-plugin-genshin：原神资料查询</li><li>koishi-plugin-ink：展示视觉小说</li><li>koishi-plugin-shell：执行终端命令</li></ul><p>这些插件共同组成了 Koishi 如今的生态。</p>',6),K=o("参见："),k=o("官方插件"),m=l("h3",{id:"多账户与跨平台支持",tabindex:"-1"},[l("a",{class:"header-anchor",href:"#多账户与跨平台支持","aria-hidden":"true"},"#"),o(" 多账户与跨平台支持")],-1),x=l("p",null,[o("Koishi 原生地支持了多账户与跨平台，同时为这些机器人之间互通数据、共用服务器、保证数据安全提供了原生的解决方案，这有助于在保持高性能的同时，将风控和迁移造成的影响降低到最小。Koishi 的用户甚至"),l("strong",null,"可以在不同的平台间绑定数据"),o("，使你无论切换到哪个平台，机器人都能记住你的用户信息。")],-1),_=l("p",null,"除此以外，Koishi 还内置了一套用户管理机制，不仅几乎能满足一切需求，还具有良好的扩展性，任何人都可以在插件中扩展用户的字段。Koishi 的模块化开发使得这套机制并不仅限于单一的平台或者数据库。目前支持的平台已经包括 QQ (OneBot)，Telegram，Discord 等等，支持的数据库包括 MySQL (mariadb) 和 MongoDB。",-1),w=o("参见："),I=o("多账户与跨平台"),j=l("h3",{id:"便利的网页控制台",tabindex:"-1"},[l("a",{class:"header-anchor",href:"#便利的网页控制台","aria-hidden":"true"},"#"),o(" 便利的网页控制台")],-1),L=l("p",null,"Koishi v3 的另一大亮点就是拥有官方的网页控制台插件。这个控制台包含了非常多的功能：查看机器人运行状态、收集并展示统计数据、管理你的插件和依赖……",-1),A=l("p",null,"这个控制台本身的也提供了接口，允许其他插件来新增页面。当你安装了另一个插件 koishi-plugin-chat 之后，你甚至可以利用控制台，直接使用机器人的号进行聊天！",-1),M=o("参见："),P=o("网页控制台"),y=l("h3",{id:"类型与单元测试",tabindex:"-1"},[l("a",{class:"header-anchor",href:"#类型与单元测试","aria-hidden":"true"},"#"),o(" 类型与单元测试")],-1),D=l("p",null,"Koishi 在开发时借助了下面的工具：",-1),Q=o("使用 "),B={href:"http://www.typescriptlang.org/",target:"_blank",rel:"noopener noreferrer"},C=o("TypeScript"),E=o(" 编写"),H=o("使用 "),O={href:"https://mochajs.org/",target:"_blank",rel:"noopener noreferrer"},R=o("Mocha"),S=o(" 进行单元测试"),T=o("使用 "),v={href:"https://eslint.org/",target:"_blank",rel:"noopener noreferrer"},F=o("Eslint"),G=o(" 进行代码风格检查"),N=o("使用 "),q={href:"https://github.com/features/actions",target:"_blank",rel:"noopener noreferrer"},z=o("GitHub Actions"),J=o(" 进行持续集成"),U=l("p",null,"这既保证了其代码的正确性和可读性，也为使用 IDE 编写 Koishi 程序提供了极大的方便。",-1);t.render=function(h,o){const t=i("RouterLink"),V=i("OutboundLink");return e(),a(n,null,[s,l("p",null,[u,l(t,{to:"/guide/starter.html"},{default:r((()=>[d])),_:1})]),p,c,l("p",null,[g,l(t,{to:"/api/"},{default:r((()=>[f])),_:1})]),b,l("p",null,[K,l(t,{to:"/plugins/"},{default:r((()=>[k])),_:1})]),m,x,_,l("p",null,[w,l(t,{to:"/guide/adapter.html"},{default:r((()=>[I])),_:1})]),j,L,A,l("p",null,[M,l(t,{to:"/plugins/other/webui.html"},{default:r((()=>[P])),_:1})]),y,D,l("ul",null,[l("li",null,[Q,l("a",B,[C,l(V)]),E]),l("li",null,[H,l("a",O,[R,l(V)]),S]),l("li",null,[T,l("a",v,[F,l(V)]),G]),l("li",null,[N,l("a",q,[z,l(V)]),J])]),U],64)};export default t;
